import{_ as t,o as l,c as r,a2 as e}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"F14: 負債結構與償債壓力測試 - 財務審計專家 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/3105_穩懋/20260503/F14_負債結構與償債壓力測試.md","filePath":"審計報告庫/財務審計/3105_穩懋/20260503/F14_負債結構與償債壓力測試.md"}'),o={name:"審計報告庫/財務審計/3105_穩懋/20260503/F14_負債結構與償債壓力測試.md"};function i(n,a,s,h,_,d){return l(),r("div",null,[...a[0]||(a[0]=[e('<p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p><h1 id="f14-負債結構與償債壓力測試-財務審計專家-審計報告" tabindex="-1">F14: 負債結構與償債壓力測試 - 財務審計專家 審計報告 <a class="header-anchor" href="#f14-負債結構與償債壓力測試-財務審計專家-審計報告" aria-label="Permalink to &quot;F14: 負債結構與償債壓力測試 - 財務審計專家 審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>負債比率與利息覆蓋倍數為何？債務到期分佈是否集中於短期？高利率環境下的利息支出承受度？</p></blockquote><h2 id="🎯-專家直斷-56-字" tabindex="-1">🎯 專家直斷（56 字） <a class="header-anchor" href="#🎯-專家直斷-56-字" aria-label="Permalink to &quot;🎯 專家直斷（56 字）&quot;">​</a></h2><ul><li><strong>核心結論</strong>：負債比 31.6%（三年最低），利息保障倍數 2.1x，短期借款僅 NT$35M（可忽略）。長借 NT$12.33B 以浮動利率為主，但現金 NT$7.07B 充裕。整體償債壓力低，分數 A 級。</li><li><strong>風險評級</strong>：低</li><li><strong>數據時效</strong>：根據截至 2025 年最新公開數據</li></ul><h2 id="📊-診斷評級-130-字" tabindex="-1">📊 診斷評級（130 字） <a class="header-anchor" href="#📊-診斷評級-130-字" aria-label="Permalink to &quot;📊 診斷評級（130 字）&quot;">​</a></h2><ul><li><strong>重點數據</strong>：負債比 50.9%→31.6%，長借 $20.03B→$12.33B（-38.5%）。短借僅 $35M 可忽略。利息保障倍數 2.1x，現金 $7,067M 覆蓋長借 57.3%。</li><li><strong>診斷見解</strong>：去槓桿成效顯著，短債清零。ICR 2.1x 不高但利息持續下降，EBITDA ICR 約 7.5x，風險可控。</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="債務結構分析" tabindex="-1">債務結構分析 <a class="header-anchor" href="#債務結構分析" aria-label="Permalink to &quot;債務結構分析&quot;">​</a></h3><ul><li><strong>核心重點</strong>：長借 NT$12,328M 佔總負債 63.6%（總負債 NT$19,386M），無短期借款壓力。長借從 2023 年高峰 NT$20.0B 降低 38.5%，年均償還 NT$3.85B。流動負債 NT$5,865M 中主要為應付款項，非金融性負債。</li><li><strong>深度見解</strong>：短期流動性無虞：現金 NT$7,067M 達流動負債的 120.5%。2025 年償還 NT$7.99B 後，2026 年到期還款壓力已大幅減輕。</li></ul><h3 id="利息承受度分析" tabindex="-1">利息承受度分析 <a class="header-anchor" href="#利息承受度分析" aria-label="Permalink to &quot;利息承受度分析&quot;">​</a></h3><ul><li><strong>核心重點</strong>：利息支出 NT$675M（2025），較 2024 年 NT$795M 減少 15.1%。以混合利率約 2.5-3.0% 估算，利率每上升 1% 將增加 NT$123M 利息支出（EPS 影響約 NT$0.2-0.25）。</li><li><strong>深度見解</strong>：1% 利率上升對 EPS 的影響約 NT$0.2-0.25，佔 2025 年 EPS NT$4.00 的 5-6%，衝擊可控。但如果利潤收縮（如營收下滑），ICR 可能降至 1.5x 以下。</li></ul><h2 id="💡-專家評析-≥2-個利空關鍵字" tabindex="-1">💡 專家評析（≥2 個利空關鍵字） <a class="header-anchor" href="#💡-專家評析-≥2-個利空關鍵字" aria-label="Permalink to &quot;💡 專家評析（≥2 個利空關鍵字）&quot;">​</a></h2><ol><li><p><strong>ICR 僅 2.1x 偏低，營益下滑時恐快速惡化</strong>：利息保障倍數 2.1x 僅略高於安全門檻（2x）。2025 年營益僅 NT$715M，利息覆蓋率不足 1.1x，幾乎所有營益用於付息。若 2026 年營收衰退 10-15%，EBIT 可能降至 NT$300-400M，ICR 將跌破 1.0x，構成技術性違約警訊。</p></li><li><p><strong>長借 NT$12.33B 仍為現金流固定負擔</strong>：每年利息支出 NT$675M，佔 CFO NT$4,953M 的 13.6%。若利用率下滑致 CFO 減少至 NT$3.0-3.5B，利息將佔 19-23%。浮動利率借款存在利率風險，若全球利率環境維持高檔，利息支出難以進一步下降。</p></li><li><p><strong>集團背書保證 NT$8.33B 形成隱含負債</strong>：母公司對子公司（尤農牧部門）背書保證合計 NT$8.33B，佔淨值 20.0%。農牧部門連年鉅額虧損（NT$1.17B），若未來發生違約，母公司需代償，將直接侵蝕淨現金部位與利息覆蓋能力。</p></li></ol><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li>計算工具：數據採集器.py (balance_sheet 3105)、(finance 3105)</li><li>年報 PDF：2025_Q4_3105_合併.pdf（借款附註 p.20-22、背書保證 p.75-76）</li><li>關鍵核對碼：負債比 31.6%, 長借 NT$12,328M, ICR=2.1x, 現金 NT$7,067M</li></ul>',17)])])}const T=t(o,[["render",i]]);export{u as __pageData,T as default};
